1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const LOYALTY_DISCOUNT_RATE = 0.2;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const BLOCK_OF_3_PRICE = 60;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
10	const DEDUCTIBLE = 100;
11	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
12	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	const INSURANCE_VALUE: Record<string, number> = {
16	  sword: 1000,
17	  amulet: 600,
18	  staff: 800,
19	  potion: 400,
20	  rune: 250,
21	  moonstone: 250,
22	};
23	
24	const BASE_PREMIUM: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	function processClaim(step: any, quoteStep: any): { payout: number; remainingCap: number } {
34	  let insuranceSum = 0;
35	  for (const item of quoteStep.items) {
36	    insuranceSum += INSURANCE_VALUE[item.type];
37	  }
38	  const cap = 2 * insuranceSum;
39	  let payout = 0;
40	  for (const damage of step.incident.damages) {
41	    const matchedItem = quoteStep.items.find((item: any) => item.type === damage.itemType);
42	    const isHighEnchantment = matchedItem && matchedItem.enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD;
43	    const reimbursement = isHighEnchantment
44	      ? damage.amount * CLAIM_HIGH_ENCHANTMENT_RATE
45	      : damage.amount;
46	    payout += reimbursement - DEDUCTIBLE;
47	  }
48	  payout = Math.floor(payout);
49	  const remainingCap = cap - payout;
50	  return { payout, remainingCap };
51	}
52	
53	export function processScenario(scenario: any): any {
54	  const results: any[] = [];
55	  let quoteCount = 0;
56	  for (const step of scenario.steps) {
57	    if (step.op === "claim") {
58	      results.push(processClaim(step, scenario.steps[step.policy]));
59	      continue;
60	    }
61	    let basePremium = 0;
62	    let curseSurcharge = 0;
63	    let highEnchantmentSurcharge = 0;
64	    const typeCounts: Record<string, number> = {};
65	    for (const item of step.items) {
66	      typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
67	      if (item.cursed) {
68	        curseSurcharge += BASE_PREMIUM[item.type] * CURSE_SURCHARGE_RATE;
69	      }
70	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
71	        highEnchantmentSurcharge += BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
72	      }
73	    }
74	    for (const [type, count] of Object.entries(typeCounts)) {
75	      const isComponentType = COMPONENT_TYPES.has(type);
76	      const formsBlockOf3 = count === 3 && isComponentType;
77	      if (formsBlockOf3) {
78	        basePremium += BLOCK_OF_3_PRICE;
79	      } else {
80	        basePremium += count * BASE_PREMIUM[type];
81	      }
82	    }
83	    let loyaltyDiscount = 0;
84	    if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
85	      loyaltyDiscount = basePremium * LOYALTY_DISCOUNT_RATE;
86	    }
87	    const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
88	    let followUpDiscount = 0;
89	    if (quoteCount > 0) {
90	      followUpDiscount = basePremium * FOLLOW_UP_DISCOUNT_RATE;
91	    }
92	    const totalSurcharges = curseSurcharge + highEnchantmentSurcharge + firstInsuranceSurcharge;
93	    const totalDiscounts = loyaltyDiscount + followUpDiscount;
94	    const premium = Math.ceil(basePremium + totalSurcharges - totalDiscounts + PROCESSING_FEE);
95	    results.push({ premium });
96	    quoteCount++;
97	  }
98	  return { results };
99	}
